function CommonIcon:SetCommonReward(rewardType, itemRefId, count, emtpyBgType, isTips)
    self._rewardType = rewardType
    self._rewardRefId = itemRefId
    self._rewardCount = tonumber(count)

    if rewardType == LItemTypeConst.TYPE_ITEM then
        --道具
        self:SetItemIcon(itemRefId, count, isTips)
    elseif rewardType == LItemTypeConst.TYPE_HERO then
        --英雄
        self:SetHeroIcon(itemRefId, count)
    elseif rewardType == LItemTypeConst.TYPE_EQUIP then
        --装备
        self:SetEquipIcon(itemRefId, count, nil, isTips)
    elseif rewardType == LItemTypeConst.TYPE_RUNE then
        --符文
        self:SetRuneIcon(itemRefId, count)
    elseif rewardType == LItemTypeConst.TYPE_OUTFIT then
        --新装备
        self:SetOutfitIcon(itemRefId, count)
    elseif rewardType == LItemTypeConst.TYPE_PET_EQUIP then
        --宠物装备
        self:SetPetEquipIcon(itemRefId, count)
    elseif rewardType == LItemTypeConst.TYPE_BADGE then--灵魂
        self:SetBadgeIcon(itemRefId, count)
    elseif rewardType == LItemTypeConst.TYPE_GOLEM then
        --魔偶
        self:SetGolemIcon(itemRefId, count)
    elseif rewardType == LItemTypeConst.TYPE_FISH then
        --鱼场
        self:SetFishIcon(itemRefId, count)
        -- 【G公共支持】删除伙伴晶石功能相关数据
        -- 【G公共支持】删除伙伴晶石功能相关数据
        -- elseif rewardType == LItemTypeConst.ICON_TYPE_CRYSTAL_SHARD or rewardType == LItemTypeConst.ICON_TYPE_CRYSTAL_DRAWING then--魔晶
        -- 	self:SetCrystalIcon(rewardType, itemRefId, count)
        -- 【C宠物系统】删掉宠物系统相关
        -- elseif rewardType == LItemTypeConst.TYPE_PET then--宠物
        -- 	self:SetPetIcon(rewardType, itemRefId, count)
    else
        --空道具类型，显示空格子加号
        self:SetEmptyItemIcon(itemRefId, count, emtpyBgType)
    end
end

function CommonIcon:SetItemData(itemdata)
    self._rewardType = itemdata.itype
    self._rewardRefId = itemdata.refId
    self._rewardCount = tonumber(itemdata.num)
    self._isShowUnlimited = itemdata.isShowUnlimited
    self:SetItemIcon(self._rewardRefId, self._rewardCount)
end

function CommonIcon:SetRewardDetailItem(itemdata)
    local itype = itemdata.itype
    if itype == LItemTypeConst.TYPE_ITEM then
        self:SetItemData(itemdata)
    elseif itype == LItemTypeConst.TYPE_HERO then
        self:SetHeroDataSet(itemdata)
    elseif itype == LItemTypeConst.TYPE_RUNE then
        self:SetRuneData(itemdata)
    elseif itype == LItemTypeConst.TYPE_OUTFIT then
        self:SetOutfitData(itemdata)
        -- 【G公共支持】删除伙伴晶石功能相关数据
        -- elseif itype == LItemTypeConst.ICON_TYPE_CRYSTAL_SHARD or itype == LItemTypeConst.ICON_TYPE_CRYSTAL_DRAWING then
        -- 	self:SetCrystalData(itemdata)
        -- 【C宠物系统】删掉宠物系统相关
        -- elseif itype == LItemTypeConst.TYPE_PET then
        -- 	self:SetPetDataSet(itemdata)
    elseif itype == LItemTypeConst.TYPE_EQUIP then
        self:SetEquipIcon(itemdata.refId, itemdata.num)
    elseif itype == LItemTypeConst.TYPE_PET_EQUIP then
        self:SetPetEquipIcon(itemdata.refId, itemdata.num)
    elseif itype == LItemTypeConst.TYPE_GOLEM then
		self:SetGolemData(itemdata)
    end
end

function CommonIcon:SetCommonItemdata(itemdata)
    self._isShowUnlimited= itemdata.isShowUnlimited
    self:SetCommonReward(itemdata.itemType, itemdata.itemId, itemdata.itemNum, itemdata.emtpyBgType)
end

function CommonIcon:EnableShowOver(show)
