function CommonIcon:SetGolemDataById(id)
	local golemInfo = gModelGolem:GetGolemServerDataById(id)
	if not golemInfo then
		return
	end

	self:ChangeIconType(CommonIcon.ICON_TYPE_GOLEM)
	local cls = self._curIconCls
	if not cls then
		return
	end
    local displayHeroBg
    local quality = gModelHero:GetHeroQualityById(golemInfo.heroId)
    if quality then
        local qualityRef = gModelItem:GetQualityRef(quality)
        displayHeroBg = qualityRef.iconBg
    end
	local data = {
		refId = golemInfo.refId,
		lvlRefId = golemInfo.lvlRefId,
		lvl = golemInfo:GetLv(),
		displayPos = gModelGolem:GetGolemElementGolemDrawingIconByRefId(golemInfo.refId),
		displayHero = gModelHero:GetHeroOutfitIconById(golemInfo.heroId),
        displayHeroBg = displayHeroBg
	}
	cls:SetGolemData(data)
end
