---@return BaseIconNew
function CommonIcon:GenerateIconCls(iconType)
    local cls
    if self._bSupportMulti then
        cls = self._iconClsList[iconType]
        if cls then
            cls:EnableHideInPos(false)
            return cls
        end
    end

    if iconType == CommonIcon.ICON_TYPE_ITEM then
        cls = ItemIconNew:New(self._ownerWndClass)
    elseif iconType == CommonIcon.ICON_TYPE_HERO then
        cls = HeroIconNew:New(self._ownerWndClass)
    elseif iconType == CommonIcon.ICON_TYPE_EQUIP then
        cls = EquipIconNew:New(self._ownerWndClass)
    elseif iconType == CommonIcon.ICON_TYPE_RUNE then
        cls = RuneIconNew:New(self._ownerWndClass)
    elseif iconType == CommonIcon.ICON_TYPE_OUTFIT then
        cls = OutfitIconNew:New(self._ownerWndClass)
    elseif iconType == CommonIcon.ICON_TYPE_EMPTY then
        cls = EmptyItemIconNew:New(self._ownerWndClass)
        -- elseif iconType == CommonIcon.ICON_TYPE_TREASURE then
        -- 	cls = TreasureIconNew:New(self._ownerWndClass)
        -- elseif iconType == CommonIcon.ICON_TYPE_TREASUREARTICLE then
        -- 	cls = TreasureIconNew:New(self._ownerWndClass)
        --elseif iconType == CommonIcon.ICON_TYPE_TREASURESKILL then
        --	cls = TreasureSkillIconNew:New(self._ownerWndClass)
    elseif iconType == CommonIcon.ICON_TYPE_GOLEM then
        cls = GolemIconNew:New(self._ownerWndClass)
        -- 【G公共支持】删除伙伴晶石功能相关数据
        -- elseif iconType == CommonIcon.ICON_TYPE_CRYSTAL_SHARD then
        -- 	cls = CrystalIconNew:New(self._ownerWndClass)
        -- 【G公共支持】删除伙伴晶石功能相关数据
        -- elseif iconType == CommonIcon.ICON_TYPE_CRYSTAL_DRAWING then
        -- 	cls = CrystalIconNew:New(self._ownerWndClass)
        -- 【C宠物系统】删掉宠物系统相关
    elseif iconType == CommonIcon.ICON_TYPE_PET_EQUIP then
        cls = PetEquipIconNew:New(self._ownerWndClass)
    elseif iconType == CommonIcon.ICON_TYPE_PET_EQUIP_Tips then
        cls = PetEquipIconNew:New(self._ownerWndClass)
    elseif iconType == CommonIcon.ICON_TYPE_PET then
        cls = PetIconNew:New(self._ownerWndClass)
    elseif iconType == CommonIcon.ICON_TYPE_FISH then
        cls = FishIconNew:New(self._ownerWndClass)
    elseif iconType == CommonIcon.ICON_TYPE_HALIDOM then
        cls = HalidomIconNew:New(self._ownerWndClass)
    elseif iconType == CommonIcon.ICON_TYPE_ITEM_Tips then
        cls = ItemIconNew:New(self._ownerWndClass)
    elseif iconType == CommonIcon.ICON_TYPE_EQUIP_Tips then
        cls = EquipIconNew:New(self._ownerWndClass)
    elseif iconType== CommonIcon.ICON_TYPE_BADGE then
        cls = BadgeIcon:New(self._ownerWndClass)
    end

    if self._bSupportMulti then
        self._iconClsList[iconType] = cls
    end
    return cls
end

function CommonIcon:GetIconArgs(iconType)
    local argsList = CommonIcon.ICON_ARGS_LIST
    if not argsList then
        argsList = {}
        local resTag = CS.RES_TAG_PERSISTENT

        argsList[CommonIcon.ICON_TYPE_ITEM] = LSimplePool.Static_MakeWndArgs(CS.ResPath(CS.RES_UI_WND, "ItemIconNew"), "ItemIconNew", resTag)
        argsList[CommonIcon.ICON_TYPE_HERO] = LSimplePool.Static_MakeWndArgs(CS.ResPath(CS.RES_UI_WND, "HeroIconNew"), "HeroIconNew", resTag)
        argsList[CommonIcon.ICON_TYPE_EQUIP] = LSimplePool.Static_MakeWndArgs(CS.ResPath(CS.RES_UI_WND, "EquipIconNew"), "EquipIconNew", resTag)
        argsList[CommonIcon.ICON_TYPE_RUNE] = LSimplePool.Static_MakeWndArgs(CS.ResPath(CS.RES_UI_WND, "RuneIconNew"), "RuneIconNew", resTag)
        argsList[CommonIcon.ICON_TYPE_OUTFIT] = LSimplePool.Static_MakeWndArgs(CS.ResPath(CS.RES_UI_WND, "OutfitIconNew"), "OutfitIconNew", resTag)
        argsList[CommonIcon.ICON_TYPE_EMPTY] = LSimplePool.Static_MakeWndArgs(CS.ResPath(CS.RES_UI_WND, "EmptyItemIconNew"), "EmptyItemIconNew", resTag)
        argsList[CommonIcon.ICON_TYPE_PET_EQUIP] = LSimplePool.Static_MakeWndArgs(CS.ResPath(CS.RES_UI_WND, "PetEquipIconNew"), "PetEquipIconNew", resTag)
        -- argsList[CommonIcon.ICON_TYPE_TREASURE] = LSimplePool.Static_MakeWndArgs(CS.ResPath(CS.RES_UI_WND,"TreasureIconNew"), "TreasureIconNew", resTag)
        -- argsList[CommonIcon.ICON_TYPE_TREASUREARTICLE] = LSimplePool.Static_MakeWndArgs(CS.ResPath(CS.RES_UI_WND,"TreasureIconNew"), "TreasureIconNew", resTag)
        --argsList[CommonIcon.ICON_TYPE_TREASURESKILL] = LSimplePool.Static_MakeWndArgs(CS.ResPath(CS.RES_UI_WND,"TreasureSkillIconNew"), "TreasureSkillIconNew", resTag)
        argsList[CommonIcon.ICON_TYPE_GOLEM] = LSimplePool.Static_MakeWndArgs(CS.ResPath(CS.RES_UI_WND, "GolemIconNew"), "GolemIconNew", resTag)
        -- 【G公共支持】删除伙伴晶石功能相关数据
        -- argsList[CommonIcon.ICON_TYPE_CRYSTAL_SHARD] = LSimplePool.Static_MakeWndArgs(CS.ResPath(CS.RES_UI_WND,"CrystalIconNew"), "CrystalIconNew", resTag)
        -- argsList[CommonIcon.ICON_TYPE_CRYSTAL_DRAWING] = LSimplePool.Static_MakeWndArgs(CS.ResPath(CS.RES_UI_WND,"CrystalIconNew"), "CrystalIconNew", resTag)
        -- 【C宠物系统】删掉宠物系统相关
        -- argsList[CommonIcon.ICON_TYPE_PET] = LSimplePool.Static_MakeWndArgs(CS.ResPath(CS.RES_UI_WND,"PetIcon"), "PetIcon", resTag)
        argsList[CommonIcon.ICON_TYPE_PET] = LSimplePool.Static_MakeWndArgs(CS.ResPath(CS.RES_UI_WND, "PetIconNew"), "PetIconNew", resTag)
        argsList[CommonIcon.ICON_TYPE_FISH] = LSimplePool.Static_MakeWndArgs(CS.ResPath(CS.RES_UI_WND, "FishIconNew"), "FishIconNew", resTag)
        argsList[CommonIcon.ICON_TYPE_HALIDOM] = LSimplePool.Static_MakeWndArgs(CS.ResPath(CS.RES_UI_WND, "HalidomIconNew"), "HalidomIconNew", resTag)
        argsList[CommonIcon.ICON_TYPE_BADGE] = LSimplePool.Static_MakeWndArgs(CS.ResPath(CS.RES_UI_WND,"BadgeIcon"), "BadgeIcon", resTag)

        --新增tips的类型
        argsList[CommonIcon.ICON_TYPE_ITEM_Tips] = LSimplePool.Static_MakeWndArgs(CS.ResPath(CS.RES_UI_WND, "ItemIconNew_Tips"), "ItemIconNew_Tips", resTag)

        argsList[CommonIcon.ICON_TYPE_EQUIP_Tips] = LSimplePool.Static_MakeWndArgs(CS.ResPath(CS.RES_UI_WND, "EquipIconNew_Tips"), "EquipIconNew_Tips", resTag)

        CommonIcon.ICON_ARGS_LIST = argsList
    end

    return argsList[iconType]
end

-----------------------------------------------------------------
function CommonIcon:ChangeIconType(newType)
    if self._curIconType ~= newType then
        self._curIconType = newType

        if self._bSupportMulti then
            if self._curIconCls then
                self._curIconCls:EnableHideInPos(true)
            end
        else
            self:ClearCurIcon()
        end

        local cls = self:GenerateIconCls(newType)
        self._curIconCls = cls
        if cls then
            cls:SetUsePool(self._bUsePool)
            cls:Create(self:GetIconArgs(newType), self._parentTrans)
        end
    else
        if self._curIconCls then
            self._curIconCls:ResetIcon()
        end
    end
end

function CommonIcon:ClearCurIcon()
    if self._curIconCls then
        self._curIconCls:Destroy()
        self._curIconCls = nil
    end
end

function CommonIcon:SetAnchoredPosition(pos)
    if self._curIconCls then
        self._curIconCls:SetAnchoredPosition(pos)
    end
end

function CommonIcon:RefreshTireValue()
    if self._curIconType ~= CommonIcon.ICON_TYPE_HERO then
        return
    end
    if self._curIconCls then
