function CommonIcon:Destroy()
    if self._isDestroy then
        return
    end

    self:ClearCurIcon()

    if self._iconClsList then
        for k, v in pairs(self._iconClsList) do
            self._iconClsList[k] = nil
            v:Destroy()
        end
    end

    table.removeall(self)
    self._isDestroy = true
end

function CommonIcon:IsDestroy()
    return self._isDestroy
end
